import { useEffect, useState } from "react";
import API from "../../api/axios";
import DashboardLayout from "../../layouts/DashboardLayout";
import {
  Button,
  TextField,
  Typography,
  Box,
  Card,
  CardContent,
} from "@mui/material";
import { useNavigate } from "react-router-dom";

export default function Projects() {
  const navigate = useNavigate();

  const [projects, setProjects] = useState([]);

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  const [userForm, setUserForm] = useState({
    username: "",
    password: "",
  });

  const fetchProjects = async () => {
    const res = await API.get("projects/");
    setProjects(res.data);
  };

  const createProject = async () => {
    await API.post("projects/create/", projectForm);
    fetchProjects();
  };

  const createProjectUser = async () => {
    await API.post("create-user/", userForm);
    alert("User Added ✅");
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  return (
    <DashboardLayout>
      {/* 🔥 TOP CARDS */}
      <Box
        sx={{
          display: "flex",
          gap: 4,
          flexWrap: "wrap",
        }}
      >
        {/* LEFT */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 2,
            borderRadius: 4,
            background: "linear-gradient(135deg, #1e3c72, #2a5298)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            <Typography variant="h6">Create Project</Typography>

            <TextField
              fullWidth
              label="Project Name"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setProjectForm({ ...projectForm, name: e.target.value })
              }
            />

            <TextField
              fullWidth
              label="Project Description"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  description: e.target.value,
                })
              }
            />

            <TextField
              fullWidth
              type="date"
              margin="normal"
              InputLabelProps={{ shrink: true }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  start_date: e.target.value,
                })
              }
            />

            <TextField
              fullWidth
              type="date"
              margin="normal"
              InputLabelProps={{ shrink: true }}
              onChange={(e) =>
                setProjectForm({
                  ...projectForm,
                  end_date: e.target.value,
                })
              }
            />

            <Button
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                background: "linear-gradient(45deg, #00c6ff, #0072ff)",
              }}
              onClick={createProject}
            >
              Create Project
            </Button>
          </CardContent>
        </Card>

        {/* RIGHT */}
        <Card
          sx={{
            flex: 1,
            minWidth: 320,
            p: 2,
            borderRadius: 4,
            background: "linear-gradient(135deg, #0f2027, #203a43)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            transform: "perspective(1000px) rotateX(5deg)",
            transition: "0.4s",
            "&:hover": {
              transform: "perspective(1000px) rotateX(0deg) scale(1.02)",
            },
          }}
        >
          <CardContent>
            <Typography variant="h6">Create Project User</Typography>

            <TextField
              fullWidth
              label="Username"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, username: e.target.value })
              }
            />

            <TextField
              fullWidth
              label="Password"
              type="password"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setUserForm({ ...userForm, password: e.target.value })
              }
            />

            <Button
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                background: "linear-gradient(45deg, #ff512f, #dd2476)",
              }}
              onClick={createProjectUser}
            >
              Add Project User
            </Button>
          </CardContent>
        </Card>
      </Box>

      {/* 🔥 PROJECT LIST CLICKABLE */}
      <Box mt={5}>
        <Typography variant="h6" color="white">
          Project List
        </Typography>

        {projects.map((p) => (
          <Box mt={5} textAlign="center">
            <Button
              variant="contained"
              sx={{
                px: 5,
                py: 1.5,
                fontSize: "16px",
                borderRadius: 3,
                background: "linear-gradient(45deg, #00c6ff, #0072ff)",
                boxShadow: "0 10px 25px rgba(0,0,0,0.3)",
              }}
              onClick={() => navigate("/admin/projects/list")}
            >
              View Project List
            </Button>
          </Box>
        ))}
      </Box>
    </DashboardLayout>
  );
}
